                <div className="absolute bottom-3 right-3 flex items-center gap-1 text-[10px] text-gray-400">
                  <span className="w-1.5 h-1.5 bg-gray-300 dark:bg-gray-700 rounded-full"></span>
                  <span className="w-1.5 h-1.5 bg-gray-300 dark:bg-gray-700 rounded-full"></span>
                </div>
